{\n251:             return endOffsets.get(partition) - currentPosition;\n252:         }\n253:         return 0;\n254:     }\n255: \n256:     private static String toJsonString(Map\u003cString, Object\u003e data) {\n257:         String json;\n258:         try {\n259:             ObjectMapper mapper = new ObjectMapper();\n260:             json = mapper.writeValueAsString(data);\n261:         } catch (JsonProcessingException e) {\n262:             json = \"Bad data can't be written as json: \" + e.getMessage();\n263:         }\n264:         return json;\n265:     }\n266: \n267:     private static synchronized String statusAsJson(\n268:         String stage,\n269:         long totalProcessed,\n270:         long consumedSinceLastRebalanced,\n271:         long remaining,\n272:         String transactionalId\n273:     ) {\n274:         Map\u003cString, Object\u003e statusData = new LinkedHashMap\u003c\u003e();\n275:         statusData.put(\"transactionalId\", transactionalId);\n276:         statusData.put(\"stage\", stage);\n277:         statusData.put(\"time\", FORMAT.format(new Date()));\n278:         statusData.put(\"totalProcessed\", totalProcessed);\n279:         statusData.put(\"consumed\", consumedSinceLastRebalanced);\n280:         statusData.put(\"remaining\", remaining);\n281:         return toJsonString(statusData);\n282:     }\n283: \n284:     private static void abortTransactionAndResetPosition(\n285:         KafkaProducer\u003cString, String\u003e producer,\n286:         KafkaConsumer\u003cString, String\u003e consumer\n287:     ) {\n288:         producer.abortTransaction();\n289:         resetToLastCommittedPositions(consumer);\n290:     }\n291: \n292:     public static void main(String[] args) {\n293:         Namespace parsedArgs = argParser().parseArgsOrFail(args);\n294:         try {\n295:             runEventLoop(parsedArgs);\n296:             Exit.exit(0);\n297:         } catch (Exception e) {\n298:             log.error(\"Shutting down after unexpected