247:     private static long messagesRemaining(KafkaConsumer<String, String> consumer, TopicPartition partition) {
248:         long currentPosition = consumer.position(partition);
249:         Map<TopicPartition, Long> endOffsets = consumer.endOffsets(singleton(partition));
250:         if (endOffsets.containsKey(partition)) {
251:             return endOffsets.get(partition) - currentPosition;
252:         }
253:         return 0;
254:     }
